const client = $('Por cliente').item.json;
const items = $input.all();
const lastCheck = client.last_rss_check ? new Date(client.last_rss_check).getTime() : 0;

const newItems = items
  .map(i => i.json)
  .filter(item => new Date(item.pubDate || item.isoDate || 0).getTime() > lastCheck)
  .slice(0, 2);

return newItems.map(item => ({
  json: {
    client_id: client.id,
    client_name: client.business_name,
    brand_guidelines: client.brand_guidelines,
    title: item.title,
    link: item.link,
    content: (item.contentSnippet || item.content || '').slice(0, 1500),
    pub_date: item.pubDate || item.isoDate,
  }
}));

