const article = $('Filtrar posts nuevos').item.json;
const claudeResp = $input.first().json;
const text = claudeResp.content?.[0]?.text || '{}';
let posts = {};
try {
  const match = text.match(/\{[\s\S]*\}/);
  posts = match ? JSON.parse(match[0]) : {};
} catch(e) { posts = {}; }

const rows = [];
if (posts.twitter?.text) rows.push({ client_id: article.client_id, platform: 'twitter', content_type: 'post', body: posts.twitter.text, source_url: article.link, status: 'pending_review' });
if (posts.linkedin?.text) rows.push({ client_id: article.client_id, platform: 'linkedin', content_type: 'post', body: posts.linkedin.text, source_url: article.link, status: 'pending_review' });
if (posts.instagram?.caption) rows.push({ client_id: article.client_id, platform: 'instagram', content_type: 'carousel', body: posts.instagram.caption, metadata: { slides: posts.instagram.slides || [] }, source_url: article.link, status: 'pending_review' });

return rows.map(r => ({ json: r }));
